export interface ParsedInbodyData {
  weightKg: number;
  bmi: number;
  bodyFatPercent: number;
  fatMassKg: number;
  muscleMassKg: number;
  boneMassKg: number;
  bmrKcal: number;
  bodyAge: number;
}

export interface ParsedWorkoutData {
  type: "WALK" | "RUN" | "CYCLING" | "STRENGTH" | "HIIT" | "OTHER";
  distanceKm: number;
  durationSeconds: number;
  avgHeartRateBpm: number;
  activeCaloriesKcal: number;
}

export async function parseInbodyImage(file: File): Promise<ParsedInbodyData> {
  assertImageFile(file);

  return {
    weightKg: 77.6,
    bmi: 25,
    bodyFatPercent: 24.1,
    fatMassKg: 18.7,
    muscleMassKg: 55.3,
    boneMassKg: 3,
    bmrKcal: 1661,
    bodyAge: 37,
  };
}

export async function parseWorkoutImage(file: File): Promise<ParsedWorkoutData> {
  assertImageFile(file);

  return {
    type: "WALK",
    distanceKm: 6.21,
    durationSeconds: 3685,
    avgHeartRateBpm: 134,
    activeCaloriesKcal: 404,
  };
}

function assertImageFile(file: File): void {
  if (file.size === 0) throw new Error("Ảnh tải lên không được để trống.");
  if (!file.type.startsWith("image/")) throw new Error("File tải lên phải là ảnh.");
}
