import { NextResponse } from "next/server";
import { prisma } from "../../../lib/prisma";
import { parseInbodyImage, parseWorkoutImage } from "../../../services/ocrService";

export const runtime = "nodejs";

const MAX_FILE_SIZE_BYTES = 10 * 1024 * 1024;
const DEMO_USER_EMAIL = "ted.tran@example.com";

export async function POST(request: Request) {
  try {
    const formData = await request.formData();
    const file = formData.get("file");
    const uploadType = formData.get("uploadType");

    if (!(file instanceof File)) {
      return NextResponse.json({ success: false, error: "MISSING_IMAGE" }, { status: 400 });
    }
    if (uploadType !== "inbody" && uploadType !== "workout") {
      return NextResponse.json({ success: false, error: "INVALID_UPLOAD_TYPE" }, { status: 400 });
    }
    if (!file.type.startsWith("image/")) {
      return NextResponse.json({ success: false, error: "FILE_MUST_BE_AN_IMAGE" }, { status: 400 });
    }
    if (file.size === 0 || file.size > MAX_FILE_SIZE_BYTES) {
      return NextResponse.json({ success: false, error: "INVALID_FILE_SIZE" }, { status: 400 });
    }

    const user = await prisma.user.upsert({
      where: { email: DEMO_USER_EMAIL },
      update: { name: "Ted Tran" },
      create: { email: DEMO_USER_EMAIL, name: "Ted Tran", sex: "MALE" },
      select: { id: true },
    });
    const fileMetadata = {
      fileName: file.name,
      mimeType: file.type,
      sizeBytes: file.size,
      provider: "vision-api-mock",
    };

    if (uploadType === "inbody") {
      const result = await parseInbodyImage(file);
      await prisma.inbodyHistory.create({
        data: {
          userId: user.id,
          measuredAt: new Date(),
          ...result,
          ocrConfidence: 0.97,
          rawOcrData: fileMetadata,
        },
      });
      return NextResponse.json({ success: true, data: result });
    }

    const result = await parseWorkoutImage(file);
    await prisma.workoutLog.create({
      data: {
        userId: user.id,
        performedAt: new Date(),
        activityType: result.type,
        distanceKm: result.distanceKm,
        durationSeconds: result.durationSeconds,
        avgPaceSecondsPerKm: Math.round(result.durationSeconds / result.distanceKm),
        avgHeartRateBpm: result.avgHeartRateBpm,
        activeCaloriesKcal: result.activeCaloriesKcal,
        sourceProvider: "STRAVA_OCR_MOCK",
        rawOcrData: fileMetadata,
      },
    });
    return NextResponse.json({ success: true, data: result });
  } catch (error) {
    console.error("Upload processing failed.", error);
    return NextResponse.json(
      { success: false, error: "UPLOAD_PROCESSING_FAILED" },
      { status: 500 },
    );
  }
}
